member.example:
Convert a float ViewModel value to a formatted string for a label

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericCasterBinder<float, string> Distance = new
        (
            value => _label.text = value,
            new FloatToStringConverter("F1")
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _distance;
    }

Target-scoped variant avoids capturing the label in a closure

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericCasterBinder<TMP_Text, float, string> Distance = new
        (
            _label,
            (label, value) => label.text = value,
            new FloatToStringConverter("F1")
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _distance;
    }

Apply the player name from the ViewModel exactly once at binding time

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericOneTimeBinder<string> Name =>
            new(value => _label.text = value);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _name;
    }

Target-scoped variant — no closure over the label

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericOneTimeBinder<TMP_Text, string> Name => new
        (
            _label,
            (label, value) => label.text = value
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _name;
    }

Update a score label each time the ViewModel value changes

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericOneWayBinder<int> Score => new(
            value => _label.text = value.ToString());
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _score;
    }

Target-scoped variant avoids capturing the label in a closure

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        
        private UnityGenericOneWayBinder<TMP_Text, int> Score => new
        (
            _label,
            (label, value) => label.text = value.ToString()
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _score;
    }

Forward toggle state changes back to the ViewModel

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Toggle _toggle;
        
        private UnityGenericOneWayToSourceBinder<bool> IsOn => new(
            onChanged => _toggle.onValueChanged.AddListener(onChanged));
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isOn;
    }

Target-scoped variant — toggle is passed to the factory, avoiding a closure

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Toggle _toggle;
        
        private UnityGenericOneWayToSourceBinder<Toggle, bool> IsOn = new
        (
            _toggle,
            (toggle, onChanged) => toggle.onValueChanged.AddListener(onChanged)
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isOn;
    }

Synchronize a slider with a ViewModel float property in both directions

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _slider;
        
        private UnityGenericTwoWayBinder<float> Value = new
        (
            onChanged => _slider.onValueChanged.AddListener(onChanged),
            value => _slider.value = value
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _value;
    }

Target-scoped variant avoids capturing the slider in a closure

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _slider;
        
        private UnityGenericTwoWayBinder<Slider, float> Value = new
        (
            _slider,
            (slider, onChanged) => slider.onValueChanged.AddListener(onChanged),
            (slider, value) => slider.value = value
        );
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _value;
    }
